#!/usr/bin/env bash
# run_all.sh — full A/B/C benchmark suite for apple-bottom.
#   Phase 1: QE SCF on si64, si64_500b, si216   (generated by generate_inputs.sh)
#   Phase 2: Yambo IP-RPA + reduced GW-PPA      (if YAMBO_SAVE_DIR set)
#   Phase 3: aggregate.sh                       (CSV, speedup table, chart)
#
# Recommended: Homebrew bash 5 (`/opt/homebrew/bin/bash run_all.sh`).
set -euo pipefail

HERE="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${HERE}/config.sh"
cd "${HERE}"

QE_SYSTEMS=(${QE_SYSTEMS:-si64 si64_500b si216})
YAMBO_SYSTEMS=(${YAMBO_SYSTEMS:-gaas})

echo "${C_BLD}##############################################${C_RST}"
echo "${C_BLD}# apple-bottom A/B/C benchmark suite          ${C_RST}"
echo "${C_BLD}# Modes: cpu (Accelerate) | gpu (forced GPU) | auto (smart)${C_RST}"
echo "${C_BLD}##############################################${C_RST}"
echo "[$(ts)] PW_BIN    = ${PW_BIN}"
echo "[$(ts)] YAMBO_BIN = ${YAMBO_BIN}"

# --- prereq checks -------------------------------------------------------
fail=0
if [[ ! -x "${PW_BIN}" ]]; then
    echo "${C_RED}[prereq]${C_RST} PW_BIN missing: ${PW_BIN} — run ./build_qe_ab.sh"
    fail=1
fi
check_applebottom_link "${PW_BIN}"
if [[ -x "${YAMBO_BIN}" ]]; then
    check_applebottom_link "${YAMBO_BIN}"
fi
(( fail )) && exit 1

# --- generate inputs if needed -------------------------------------------
if [[ ! -d "${BENCH_INPUT_DIR}" ]] || [[ -z "$(ls -A "${BENCH_INPUT_DIR}" 2>/dev/null)" ]]; then
    echo ""
    echo "[$(ts)] ${C_BLU}Generating QE inputs...${C_RST}"
    ./generate_inputs.sh
fi

# --- Phase 1: QE --------------------------------------------------------
echo ""
echo "${C_BLD}=== Phase 1: QE SCF benchmarks ===${C_RST}"
for sys in "${QE_SYSTEMS[@]}"; do
    echo ""
    ./bench_qe.sh "${sys}" --timeout "${QE_TIMEOUT}" \
        || echo "${C_YLW}(qe ${sys} had failures — continuing)${C_RST}"
done

# --- Phase 2: Yambo (optional) ------------------------------------------
if [[ -x "${YAMBO_BIN}" ]] && { [[ -n "${YAMBO_SAVE_DIR:-}" ]] || yambo_template_dir "${YAMBO_SYSTEMS[0]}" >/dev/null 2>&1; }; then
    echo ""
    echo "${C_BLD}=== Phase 2: Yambo benchmarks ===${C_RST}"
    for sys in "${YAMBO_SYSTEMS[@]}"; do
        echo ""
        ./bench_yambo.sh "${sys}" \
            || echo "${C_YLW}(yambo ${sys} had failures — continuing)${C_RST}"
    done
else
    echo ""
    echo "${C_YLW}[skip Phase 2]${C_RST} No Yambo SAVE available."
    echo "  Set YAMBO_SAVE_DIR=/path/to/SAVE to include Yambo in the suite."
fi

# --- Phase 3: aggregate -------------------------------------------------
echo ""
echo "${C_BLD}=== Phase 3: aggregating results ===${C_RST}"
./aggregate.sh
